#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T, N, i, j, u, v, min_unattractiveness;
    int markers[MAX_N], edges[MAX_N - 1][2];

    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (i = 0; i < N; i++) {
            scanf("%d", &markers[i]);
        }
        for (i = 0; i < N - 1; i++) {
            scanf("%d %d", &u, &v);
            edges[i][0] = u;
            edges[i][1] = v;
        }
        qsort(markers, N, sizeof(int), compare);
        min_unattractiveness = 0;
        for (i = 0; i < N - 1; i++) {
            u = edges[i][0] - 1;
            v = edges[i][1] - 1;
            if (abs(markers[u] - markers[v]) > min_unattractiveness) {
                min_unattractiveness = abs(markers[u] - markers[v]);
            }
        }
        printf("%d\n", min_unattractiveness);
    }
    return 0;
}

