import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] markers = new int[N];
            for (int i = 0; i < N; i++) {
                markers[i] = scanner.nextInt();
            }
            int[][] edges = new int[N - 1][2];
            for (int i = 0; i < N - 1; i++) {
                edges[i][0] = scanner.nextInt();
                edges[i][1] = scanner.nextInt();
            }
            Arrays.sort(markers);
            int min_unattractiveness = 0;
            for (int i = 0; i < N - 1; i++) {
                int u = edges[i][0] - 1;
                int v = edges[i][1] - 1;
                if (Math.abs(markers[u] - markers[v]) > min_unattractiveness) {
                    min_unattractiveness = Math.abs(markers[u] - markers[v]);
                }
            }
            System.out.println(min_unattractiveness);
        }
    }
}

